import{_ as e,c as i,o,a0 as n}from"./chunks/framework.d22c6mgx.js";const g=JSON.parse('{"title":"XiaoZhi External MCP Integration Guide","description":"","frontmatter":{},"headers":[],"relativePath":"mcp/xiaozhi-mcp.md","filePath":"mcp/xiaozhi-mcp.md"}'),a={name:"mcp/xiaozhi-mcp.md"};function r(l,t,s,c,p,h){return o(),i("div",null,t[0]||(t[0]=[n(`<h1 id="xiaozhi-external-mcp-integration-guide" tabindex="-1">XiaoZhi External MCP Integration Guide <a class="header-anchor" href="#xiaozhi-external-mcp-integration-guide" aria-label="Permalink to &quot;XiaoZhi External MCP Integration Guide&quot;">​</a></h1><p>This document describes how to integrate external MCP services into the XiaoZhi system for feature extension and third-party tool integration.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>In addition to built-in MCP tools, the XiaoZhi system also supports connecting to external MCP servers, enabling:</p><ul><li>Third-party tool integration</li><li>Remote service invocation</li><li>Distributed tool deployment</li><li>Community tool sharing</li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><h3 id="external-mcp-architecture" tabindex="-1">External MCP Architecture <a class="header-anchor" href="#external-mcp-architecture" aria-label="Permalink to &quot;External MCP Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>XiaoZhi AI Platform     xiaozhi-mcphub          External MCP Server       Third-Party Tools</span></span>
<span class="line"><span>┌─────────────┐        ┌─────────────────┐      ┌─────────────────┐      ┌─────────────┐</span></span>
<span class="line"><span>│             │        │                 │      │                 │      │             │</span></span>
<span class="line"><span>│ MCP Client  │◄───────┤ MCP Server/Proxy│◄─────┤ MCP Server      │◄─────┤ Actual Tools│</span></span>
<span class="line"><span>│             │        │                 │      │                 │      │             │</span></span>
<span class="line"><span>└─────────────┘        └─────────────────┘      └─────────────────┘      └─────────────┘</span></span></code></pre></div><h3 id="connection-methods" tabindex="-1">Connection Methods <a class="header-anchor" href="#connection-methods" aria-label="Permalink to &quot;Connection Methods&quot;">​</a></h3><ol><li><strong>Standard Input/Output (stdio)</strong>: Launches a subprocess and communicates via stdin/stdout pipes for inter-process communication. Suitable for local CLI tools such as Playwright, Amap, etc.</li><li><strong>Server-Sent Events (SSE)</strong>: HTTP long-connection based event stream communication, providing real-time bidirectional communication similar to WebSocket</li><li><strong>Streamable HTTP (streamable-http)</strong>: HTTP protocol encapsulation over TCP, supporting streaming data transmission. Suitable for remote API services and microservices</li><li><strong>OpenAPI</strong>: Connection based on standard REST API specifications, automatically parsing OpenAPI specifications and generating tool interfaces. Suitable for standardized third-party API services</li></ol><h2 id="related-open-source-projects" tabindex="-1">Related Open-Source Projects <a class="header-anchor" href="#related-open-source-projects" aria-label="Permalink to &quot;Related Open-Source Projects&quot;">​</a></h2><p>Community-developed XiaoZhi client projects providing integration methods for different platforms</p><h3 id="xiaozhi-mcphub-companion-project" tabindex="-1">xiaozhi-mcphub (Companion Project) <a class="header-anchor" href="#xiaozhi-mcphub-companion-project" aria-label="Permalink to &quot;xiaozhi-mcphub (Companion Project)&quot;">​</a></h3><p><strong>XiaoZhi MCP Hub</strong> is an intelligent MCP tool bridge system optimized for the XiaoZhi AI platform, built on the excellent MCPHub project with added XiaoZhi platform integration and intelligent tool synchronization features.</p><ul><li><strong>Project Site</strong>: <a href="https://huangjunsen0406.github.io/xiaozhi-mcphub/" target="_blank" rel="noreferrer">xiaozhi-mcphub</a></li><li><strong>GitHub</strong>: <a href="https://github.com/huangjunsen0406/xiaozhi-mcphub" target="_blank" rel="noreferrer">xiaozhi-mcphub</a></li><li><strong>Core Features</strong>: <ul><li><strong>XiaoZhi AI Platform Integration</strong>: WebSocket automatic tool synchronization, real-time status updates, protocol bridging</li><li><strong>Enhanced MCP Management</strong>: Supports stdio, SSE, HTTP protocols, hot-swap configuration, centralized console</li><li><strong>Smart Tool Routing</strong>: Vector-based intelligent tool search and group management</li><li><strong>Security Authentication</strong>: JWT + bcrypt user management, role-based access control</li><li><strong>Built-in MCP Store</strong>: Various MCP tools available for online installation with hot updates, no restart required</li></ul></li></ul><h3 id="xiaozhi-client" tabindex="-1">xiaozhi-client <a class="header-anchor" href="#xiaozhi-client" aria-label="Permalink to &quot;xiaozhi-client&quot;">​</a></h3><ul><li><strong>Project Repository</strong>: <a href="https://github.com/shenjingnan/xiaozhi-client" target="_blank" rel="noreferrer">xiaozhi-client</a></li><li><strong>Function</strong>: XiaoZhi AI client, specifically designed for MCP integration and aggregation</li><li><strong>Core Features</strong>: <ul><li><strong>Multi-Endpoint Support</strong>: Configurable multiple XiaoZhi endpoints, enabling multiple devices to share a single MCP configuration</li><li><strong>MCP Server Aggregation</strong>: Aggregates multiple MCP Servers through standard methods for unified management</li><li><strong>Dynamic Tool Control</strong>: Controls MCP Server tool visibility to avoid issues caused by too many tools</li><li><strong>Multiple Integration Methods</strong>: Supports integration as a regular MCP Server into clients like Cursor/Cherry Studio</li><li><strong>Web Visual Configuration</strong>: Modern web UI interface supporting remote configuration and management</li><li><strong>ModelScope Integration</strong>: Supports ModelScope-hosted remote MCP services</li></ul></li></ul><h3 id="hyperchat" tabindex="-1">HyperChat <a class="header-anchor" href="#hyperchat" aria-label="Permalink to &quot;HyperChat&quot;">​</a></h3><ul><li><strong>Project Site</strong>: <a href="https://github.com/BigSweetPotatoStudio/HyperChat" target="_blank" rel="noreferrer">HyperChat</a></li><li><strong>Function</strong>: Next-generation AI workspace, pioneering the &quot;AI as Code&quot; concept for a multi-platform intelligent collaboration platform</li><li><strong>Core Features</strong>: <ul><li><strong>AI as Code</strong>: Configuration-driven AI capability management, supporting version control and team collaboration</li><li><strong>Workspace-Driven</strong>: Project-centric AI environment isolation and management</li><li><strong>MCP Ecosystem Deep Integration</strong>: Full MCP protocol support, rich built-in tools, and dynamic loading</li><li><strong>Multi-Platform Unified</strong>: Web application, Electron desktop, CLI command-line, VSCode extension</li></ul></li><li><strong>Technical Highlights</strong>: <ul><li>Configurable AI agent system with specialized Agent customization</li><li>Multi-model parallel comparison testing (Claude, OpenAI, Gemini, etc.)</li><li>Intelligent content rendering (Artifacts, Mermaid, mathematical formulas)</li><li>Scheduled tasks and workflow automation</li></ul></li></ul>`,19)]))}const d=e(a,[["render",r]]);export{g as __pageData,d as default};
